def flatten(items):
    out = []
    for item in items:
        if isinstance(item, list):
            out.extend(flatten(item))
        else:
            out.append(item)
    return out

def parse_ini(text):
    out = {}
    section = ''
    for raw in text.splitlines():
        line = raw.strip()
        if not line or line[0] in ';#':
            continue
        if line.startswith('[') and line.endswith(']'):
            section = line[1:-1].strip()
            out.setdefault(section, {})
            continue
        if '=' in line:
            key, value = line.split('=', 1)
            out.setdefault(section, {})[key.strip()] = value.strip()
    return out

def glob_match(pattern, text):
    memo = {}
    def go(i, j):
        if (i, j) in memo:
            return memo[(i, j)]
        if i == len(pattern):
            ans = j == len(text)
        elif pattern[i] == '*':
            ans = go(i + 1, j) or (j < len(text) and go(i, j + 1))
        elif j < len(text) and pattern[i] in ('?', text[j]):
            ans = go(i + 1, j + 1)
        else:
            ans = False
        memo[(i, j)] = ans
        return ans
    return go(0, 0)

def parse_csv_line(line):
    fields = []
    cur = []
    in_quotes = False
    i = 0
    while i < len(line):
        ch = line[i]
        if in_quotes:
            if ch == '"':
                if i + 1 < len(line) and line[i + 1] == '"':
                    cur.append('"')
                    i += 2
                    continue
                in_quotes = False
            else:
                cur.append(ch)
        elif ch == '"':
            in_quotes = True
        elif ch == ',':
            fields.append(''.join(cur))
            cur = []
        else:
            cur.append(ch)
        i += 1
    fields.append(''.join(cur))
    return fields

def is_balanced(s):
    pairs = {')': '(', ']': '[', '}': '{'}
    stack = []
    for ch in s:
        if ch in '([{':
            stack.append(ch)
        elif ch in pairs:
            if not stack or stack.pop() != pairs[ch]:
                return False
    return not stack

def run(events):
    state = 'locked'
    entries = 0
    for event in events:
        if state == 'locked' and event == 'coin':
            state = 'unlocked'
        elif state == 'unlocked' and event == 'push':
            state = 'locked'
            entries += 1
    return (state, entries)

