def to_roman(n):
    if not 1 <= n <= 3999:
        raise ValueError('out of range')
    table = [(1000, 'M'), (900, 'CM'), (500, 'D'), (400, 'CD'),
             (100, 'C'), (90, 'XC'), (50, 'L'), (40, 'XL'),
             (10, 'X'), (9, 'IX'), (5, 'V'), (4, 'IV'), (1, 'I')]
    out = []
    for value, symbol in table:
        while n >= value:
            out.append(symbol)
            n -= value
    return ''.join(out)
